```c
#include <stdio.h>
#include <math.h>

#define PI 3.14159265358979323846

void generateTunnelProfile(double *x, double *y, double *z, int n, double radius, double thickness) {
   int i;
   double angle, angleStep = 2.0 * PI / n;

   // Generate circle points and place them in 3D space
   for (i = 0; i < n; i++) {
      angle = i * angleStep;

      x[i] = (radius + thickness * cos(angle)) * cos(angle);
      y[i] = (radius + thickness * cos(angle)) * sin(angle);
      z[i] = thickness * sin(angle);
   }
}

int main() {
   int i, n = 36; // number of points to generate
   double radius = 5.0, thickness = 1.0;
   double x[n], y[n], z[n];

   // Generate tunnel profile
   generateTunnelProfile(x, y, z, n, radius, thickness);

   // Print header
   printf("X,Y,Z\n");

   // Print tunnel profile points to console
   for (i = 0; i < n; i++) {
      printf("%.2f,%.2f,%.2f\n", x[i], y[i], z[i]);
   }

   return 0;
}
```

